#![expect(clippy::same_length_and_capacity, reason = "generated by wit-bindgen")]

wit_bindgen::generate!({
    path: "../../packages/plugin-abi-bench/wit/packed",
    world: "plugin",
});

use exports::lix::abi_bench_packed::api::Guest;

const MAGIC: &[u8; 4] = b"LPK1";
const VERSION: u16 = 1;
const HEADER_LEN: usize = 32;

struct PackedGuest;

impl Guest for PackedGuest {
    fn detect_empty(input: Vec<u8>) -> Result<Vec<u8>, String> {
        validate(&input)?;
        std::hint::black_box(input.len());
        Ok(Vec::new())
    }

    fn entity_round_trip(mut input: Vec<u8>) -> Result<Vec<u8>, String> {
        validate(&input)?;
        // Mark the packet as a change packet. No fields are copied.
        input[6..8].copy_from_slice(&2_u16.to_le_bytes());
        Ok(input)
    }

    fn file_round_trip(input: Vec<u8>) -> Result<Vec<u8>, String> {
        validate(&input)?;
        Ok(input)
    }
}

fn validate(input: &[u8]) -> Result<(), String> {
    if input.len() < HEADER_LEN || &input[..4] != MAGIC {
        return Err("invalid packed arena magic".to_string());
    }
    let version = u16::from_le_bytes([input[4], input[5]]);
    if version != VERSION {
        return Err("unsupported packed arena version".to_string());
    }
    let encoded_len = u32::from_le_bytes([input[24], input[25], input[26], input[27]]) as usize;
    if encoded_len != input.len() {
        return Err("packed arena length mismatch".to_string());
    }
    Ok(())
}

export!(PackedGuest);
